## Testing Strategy

### Unit Tests (Comprehensive)
\`\`\`rust
#[cfg(test)]
mod visible_width_tests {
    use super::visible_width;

    // Plain text
    #[test]
    fn plain_ascii() {
        assert_eq!(visible_width("hello"), 5);
        assert_eq!(visible_width(""), 0);
        assert_eq!(visible_width(" "), 1);
    }

    #[test]
    fn plain_unicode() {
        assert_eq!(visible_width("日本語"), 6);      // CJK
        assert_eq!(visible_width("café"), 4);       // Accented
        assert_eq!(visible_width("🎉"), 2);         // Emoji
        assert_eq!(visible_width("e\\u{0301}"), 1); // Combining mark
    }

    // SGR (Select Graphic Rendition) sequences
    #[test]
    fn sgr_colors() {
        assert_eq!(visible_width("\\x1b[31mred\\x1b[0m"), 3);
        assert_eq!(visible_width("\\x1b[1;32;44mbold green on blue\\x1b[0m"), 18);
    }

    #[test]
    fn sgr_256_color() {
        assert_eq!(visible_width("\\x1b[38;5;196mred256\\x1b[0m"), 6);
    }

    #[test]
    fn sgr_rgb_color() {
        assert_eq!(visible_width("\\x1b[38;2;255;0;0mrgb red\\x1b[0m"), 7);
    }

    // CSI (Control Sequence Introducer) sequences
    #[test]
    fn csi_cursor_movement() {
        assert_eq!(visible_width("\\x1b[10Ctext"), 4);  // Cursor forward
        assert_eq!(visible_width("\\x1b[2Jcleared"), 7);  // Clear screen
    }

    // OSC (Operating System Command) sequences
    #[test]
    fn osc_window_title() {
        assert_eq!(visible_width("\\x1b]0;My Title\\x07text"), 4);
        assert_eq!(visible_width("\\x1b]0;My Title\\x1b\\\\text"), 4);  // ST terminator
    }

    #[test]
    fn osc_hyperlink() {
        // OSC 8 hyperlinks
        assert_eq!(visible_width("\\x1b]8;;https://example.com\\x07link\\x1b]8;;\\x07"), 4);
    }

    // Edge cases
    #[test]
    fn empty_and_whitespace() {
        assert_eq!(visible_width(""), 0);
        assert_eq!(visible_width("   "), 3);
        assert_eq!(visible_width("\\t"), 1);  // Tab = 1 character
    }

    #[test]
    fn mixed_content() {
        let mixed = "\\x1b[31m日本語\\x1b[0m and text";
        assert_eq!(visible_width(mixed), 15);  // 6 (JP) + 9 ( and text)
    }

    #[test]
    fn malformed_escapes() {
        // Incomplete escape - should count visible parts
        assert_eq!(visible_width("\\x1b"), 0);
        assert_eq!(visible_width("\\x1b["), 0);
        assert_eq!(visible_width("text\\x1b"), 4);
    }

    // Performance fast path
    #[test]
    fn ascii_fast_path() {
        let ascii = "a".repeat(1000);
        assert_eq!(visible_width(&ascii), 1000);
    }
}
